import React from 'react'
import { Outlet, Link } from 'react-router-dom';
import BottomNavigation from '@mui/material/BottomNavigation';
import BottomNavigationAction from '@mui/material/BottomNavigationAction';
import HomeRoundedIcon from '@mui/icons-material/HomeRounded';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import SwapHorizRoundedIcon from '@mui/icons-material/SwapHorizRounded';
import PersonRoundedIcon from '@mui/icons-material/PersonRounded';
import Paper from '@mui/material/Paper';
import appTheme from '../theme';


const NavBar = () => {

  const [value, setValue] = React.useState(0);

  const iconStyles = {
    color: appTheme.palette.primary.contrastText,
  };

  const selectedIconStyles = {
    color: appTheme.palette.primary.background,
    backgroundColor: appTheme.palette.primary.contrastText,
    borderRadius: '20px',
    fontSize: '40px',
    p: '2px'

  };

  return (
    <>
    
          <Paper sx={{ position: 'fixed', bottom: 0, left: 0, right: 0 }} elevation={3}>
          <BottomNavigation
            value={value}
            onChange={(event, newValue) => setValue(newValue)}
            sx={{
              backgroundColor: appTheme.palette.primary.background
            }}
    
          >
            <BottomNavigationAction
              component={Link}
              to="/"
              icon={<HomeRoundedIcon sx={value === 0 ? selectedIconStyles : iconStyles}/>}
              
            
            />
            <BottomNavigationAction
              component={Link}
              to="/search"
              icon={<SearchRoundedIcon sx={value === 1 ? selectedIconStyles : iconStyles}/>}
            />
            <BottomNavigationAction
              component={Link}
              to="/matches"
              icon={<SwapHorizRoundedIcon sx={value === 2 ? selectedIconStyles : iconStyles}/>}
            />
            <BottomNavigationAction
              component={Link}
              to="/profile"
              icon={<PersonRoundedIcon sx={value === 3 ? selectedIconStyles : iconStyles}/>}
            />
          </BottomNavigation>
          </Paper>
    
        <Outlet></Outlet>
    </>
  )
}

export default NavBar
